// Event: Before Build PDF (daftar view)
function BeforeBuildPDF(pdfDoc) {
    // Fungsi rekursif untuk mencari dan mengubah layout 'vrecord' menjadi 'noBorders'
    function removeBorders(obj) {
        if (typeof obj !== 'object' || obj === null) {
            return;
        }

        // Jika objek memiliki property 'layout' dengan nilai 'vrecord'
        if (obj.hasOwnProperty('layout') && obj.layout === 'vrecord') {
            obj.layout = 'noBorders';
            console.log('Changed layout from vrecord to noBorders');
        }

        // Iterasi semua property
        for (var key in obj) {
            if (obj.hasOwnProperty(key)) {
                var value = obj[key];

                // Jika array, iterasi setiap elemen
                if (Array.isArray(value)) {
                    for (var i = 0; i < value.length; i++) {
                        removeBorders(value[i]);
                    }
                } 
                // Jika object, rekursif
                else if (typeof value === 'object') {
                    removeBorders(value);
                }
            }
        }
    }

    // Proses seluruh dokumen PDF
    removeBorders(pdfDoc);

    return true;
}

